            ResizeWith = 200,
            ResizeHeight = 200,
        });

        var result = service.GetImageEmbedData("test.svg");

        string expected = """
            
            """;

        Assert.Multiple(() =>
        {
            Assert.That(result.ImageType, Is.EqualTo(ImageType.Png));
            Assert.That(result.Data, Is.EqualTo(expected));
        });
    }

