        var service = new ImgService(_testFolder, _mockLogger.Object, new ImageConfig
        {
            ResizeAndRecodeImages = ImgRecodeOption.AsWebp,
            ResizeHeight = 100,
            ResizeWith = 200,
            ImageQualityOnResize = 80,
        });

        var result = service.GetImageEmbedData("test.png");

        string expected = """
            
            """;

        Assert.Multiple(() =>
